#include <iostream>

class Fraction {
    int m_numerator{};
    int m_denominator{ 1 };
public:
    Fraction(int num, int den) : m_numerator{ num }, m_denominator{ den } {}
    int getNumerator() const { return m_numerator; }
    int getDenominator() const { return m_denominator; }
};

Fraction operator+(const Fraction& a, const Fraction& b)
{
    return Fraction{
        a.getNumerator() * b.getDenominator() + b.getNumerator() * a.getDenominator(),
        a.getDenominator() * b.getDenominator()
    };
}

Fraction operator-(const Fraction& a, const Fraction& b)
{
    return Fraction{
        a.getNumerator() * b.getDenominator() - b.getNumerator() * a.getDenominator(),
        a.getDenominator() * b.getDenominator()
    };
}

int main()
{
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;

    Fraction a{ n1, d1 };
    Fraction b{ n2, d2 };

    Fraction sum{ a + b };
    Fraction diff{ a - b };

    std::cout << sum.getNumerator() << '/' << sum.getDenominator() << '\n';
    std::cout << diff.getNumerator() << '/' << diff.getDenominator() << '\n';

    return 0;
}

